      "talks": [
        {
          "easychair_id": "311647",
          "time": "13:15",
          "title": "Internationalisation for Good: How to Sustainably Foster Global Perspectives as Academic Developers",
          "authors": "Angelika Thielsch, Lucie Weissowa, Gabriela Pleschova",
          "presenter": "Angelika Thielsch",
          "abstract": "Academic developers (ADs) face a paradoxical task: they seek to promote student learning while working primarily with faculty members rather than directly with students. This distance between ADs’ professional discourse and students’ lived learning experiences is reflected in the often-overlooked role of academic development in institutional internationalisation strategies. Approaches such as the internationalisation of the curriculum at home (IoCaH) aim to transform the student experience, for example through virtual mobility or virtual exchange. However, sustainable internationalisation requires attention to the interplay between studying, teaching, and academic development. Academic developers play an essential role in this process, yet there remains a need for comprehensive institutional approaches that recognise professional learning as a continuous, active, social, and practice-based endeavour. ADs therefore need to be aware of their own roles and agency in internationalisation efforts, as do their partners across the institution. This pre-conference workshop aims to foster such awareness and to highlight the importance of ADs’ involvement in internationalisation processes that align with institutional commitments to equity, diversity, and inclusion.",
          "keywords": ""
        }
      ],
      "easychair_session_id": "106022"
