      "meet": "https://meet.google.com/tpx-uiia-jne",
      "talks": [
        {
          "easychair_id": "314176",
          "time": "16:30",
          "title": "Structural Agency in Academic Writing",
          "authors": "Helen Sword",
          "presenter": "",
          "abstract": "Structure is everywhere around us, shaping our experience of the world: in the soaring arches of a cathedral, the whirling waves of a symphony, the gossamer strands of a spider’s web. It’s everywhere in our writing, too, from the syntax of our sentences to the arc of our arguments. Yet many academic writers — from undergraduate students to distinguished faculty — have never learned to speak the intricate language of structural design. Constrained by disciplinary conventions, they remain passive inhabitants of received forms rather than confident agents of change. This 3-hour pre-conference workshop, led by international writing expert Helen Sword, invites educational developers to rethink structure both in their own practice and in their work with faculty and students. Through a series of playful “Structure Studio” exercises, participants will explore eight dimensions of structural design in academic writing — from foundational principles to generative processes to published products to future possibilities — and experiment with a variety of structural paradigms and forms. By the end of the session, you will have developed a rich new vocabulary of structural design and a practical toolbox of strategies applicable to any task that requires wrangling multiple parts into a coherent whole: writing a book or article, planning a seminar or syllabus, leading a collaborative research project, balancing a complex workload, or empowering your colleagues and students to do any of the above.",
          "keywords": ""
        }
      ],
      "easychair_session_id": "106028"
